import {
  Component,
  Element,
  Event,
  EventEmitter,
  Prop,
  State,
  Host,
  h
} from '@stencil/core';
import {
  determineMessageDismissalButtonVariant,
  dismissalButtonInMessageShouldBeInverse
} from '@src/utils/kds-utils/colorUtils';

const TagConversionMap: Record<string, any> = {
  default: { kind: 'subtle', palette: 'neutral', variant: 'fill' },
  special: { kind: 'subtle', palette: 'special', variant: 'fill' },
  positive: { kind: 'subtle', palette: 'positive', variant: 'fill' },
  callout: { kind: 'subtle', palette: 'callout', variant: 'fill' },
  neutral: { kind: 'subtle', palette: 'informative', variant: 'fill' },
  negative: { kind: 'subtle', palette: 'negative', variant: 'fill' },
  action: { kind: 'subtle', palette: 'accent', variant: 'fill' },
  interactive: { kind: 'subtle', palette: 'accent', variant: 'fill' }
};


interface KdsTagHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

@Component({
  tag: 'kds-tag',
  styleUrl: 'kds-tag.css'
})
export class KdsTag {
  @Element() hostEl: KdsTagHostElement;

  /** Sets the color palette. */
    // prettier-ignore
  @Prop({ mutable: true }) palette: 'neutral' | 'brand' | 'accent' | 'positive' | 'negative' | 'informative' | 'callout' | 'special' = 'accent';
  /** Sets the color kind. */
  @Prop({ mutable: true }) kind: 'dominant' | 'prominent' | 'subtle' | 'alternate' | 'special'
    | 'default'
    | 'positive'
    | 'callout'
    | 'negative'
    | 'action'
    | 'neutral'
    | 'interactive' = 'prominent';
  /** Sets the color variant. */
  @Prop({ mutable: true }) variant: 'fill' | 'border' = 'fill';
  /** Applies the inverse color styling. */
  @Prop({ mutable: true }) inverse: boolean = false;
  /** Defines icon to show left of the text. */
  @Prop({ mutable: true }) icon: string;
  /** Applies the compact size. */
  @Prop() readonly compact?: boolean = false;
  /** Adds a dismissal button to the tag. */
  @Prop({ mutable: true }) dismissable?: boolean = false;

  /** Determines whether tag removes itself when removal button is clicked. */
  @Prop() readonly removeSelf?: boolean = true;

  @State() ariaMessage: string;

  /** An event fired when a user removes a tag. */
  @Event() tagRemoved: EventEmitter;

  onRemoveTagClick = () => {
    this.tagRemoved.emit();
    this.removeSelf && this.hostEl.remove();
  };

  componentWillLoad() {
    this.ariaMessage = this.hostEl.textContent;

    if (TagConversionMap[this.kind]) {
      this.dismissable = this.kind === 'action';
      this.palette = TagConversionMap[this.kind].palette;
      this.variant = TagConversionMap[this.kind].variant;
      this.inverse = TagConversionMap[this.kind].inverse;
      this.kind = TagConversionMap[this.kind].kind;
    }
  }

  render() {
    const { icon: Icon } = this;
    const dismissalButtonClasses = {
      [`palette-${this.palette}`]: true,
      [`kind-${this.kind}`]: true,
      [`variant-${determineMessageDismissalButtonVariant({
        messageInverseState: this.inverse,
        //@ts-ignore
        messageKind: this.kind,
        messageVariant: this.variant
      })}`]: true,
      interactive: true,
      'as-inverse': dismissalButtonInMessageShouldBeInverse({
        messageInverseState: this.inverse,
        //@ts-ignore
        messageKind: this.kind,
        messageVariant: this.variant
      }),
      'kds-DismissalButton': true,
      'kds-Tag-dismissalButton': true
    };

    return (
      <Host
        class={{
          'kds-Tag': true,
          'kds-Tag--compact': this.compact,
          [`palette-${this.palette}`]: true,
          [`kind-${this.kind}`]: true,
          [`variant-${this.variant}`]: true,
          'as-inverse': this.inverse
        }}
        role='note'
        aria-label={`Tag: ${this.ariaMessage}`}
        style={{ lineHeight: '0' }}
      >
        {Icon && <Icon class='kds-Tag-Icon mr-4' size='s' />}
        <span class='kds-Tag-text'>
          <slot />
        </span>
        {!this.compact && this.dismissable && (
          <button
            aria-label='Select to remove tag'
            onClick={this.onRemoveTagClick}
            class={{
              ...dismissalButtonClasses
            }}
          >
            <kds-icon-close size='xs' />
          </button>
        )}
      </Host>
    );
  }
}
